prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?task1 ?task1Name ?task2 ?task2Name (COUNT(DISTINCT ?pathStart) AS ?reachableCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa".
  ?model bbo:name ?modelName .

  ?task1 a bboExt:ChoreographyTask ;
         bbo:name ?task1Name ;
         tai:belongsTo ?choreo.
  FILTER(CONTAINS(LCASE(STR(?task1Name)), "laskku"))

  ?task2 a bboExt:ChoreographyTask ;
         bbo:name ?task2Name ;
         tai:belongsTo ?choreo.
  FILTER(CONTAINS(LCASE(STR(?task2Name)), "merkitse varus"))

  # Check reachability from task 'Merkitse varus' to task 'Laskku' within same choreography
  ?task2 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task1 .
  OPTIONAL { ?task1 bbo:id ?pathStart . }
}
GROUP BY ?model ?modelName ?task1 ?task1Name ?task2 ?task2Name
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?name (COALESCE(?cmt, "") AS ?comment) ?type WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?elem tai:belongsTo ?choreo .
  ?elem a ?type .

  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem rdfs:comment ?cmt . }

  FILTER(BOUND(?name) && STRLEN(STR(?name)) > 0)
}
ORDER BY LCASE(STR(?name))
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orig ?norm WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model tai:normalizedId ?norm . }
  FILTER(
    STR(?norm) = "6e8e145a4f51488c81c0c89e863a27fa" ||
    STR(?orig) = "6e8e145a4f51488c81c0c89e863a27fa"
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?eid ?label ?comment ?type WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?elem tai:belongsTo ?choreo .
  ?elem a ?type .

  OPTIONAL { ?elem bbo:id ?eid . }
  OPTIONAL { ?elem bbo:name ?label . }
  OPTIONAL { ?elem rdfs:comment ?comment . }

  FILTER(
    (BOUND(?label) && STRLEN(STR(?label))>0 && (CONTAINS(LCASE(STR(?label)), "laskku") || CONTAINS(LCASE(STR(?label)), "merkitse varus")))
    ||
    (BOUND(?comment) && STRLEN(STR(?comment))>0 && (CONTAINS(LCASE(STR(?comment)), "laskku") || CONTAINS(LCASE(STR(?comment)), "merkitse varus")))
    ||
    (BOUND(?eid) && (CONTAINS(LCASE(STR(?eid)), "laskku") || CONTAINS(LCASE(STR(?eid)), "merkitse varus")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskId ?taskName ?prop ?val WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:id ?taskId . }
  OPTIONAL { ?task bbo:name ?taskName . }
  ?task ?prop ?val .
  FILTER(
    isLiteral(?val) &&
    (STRLEN(STR(?val)) < 120)
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
}
ORDER BY LCASE(STR(?taskName))
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskId ?litProp ?litVal WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6e8e145a4f51488c81c0c89e863a27fa" .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:id ?taskId . }

  ?task ?litProp ?litVal .
  FILTER(isLiteral(?litVal))
  FILTER( STRLEN(STR(?litVal)) < 200 )
  FILTER(
    CONTAINS(LCASE(STR(?litVal)), "laskku") ||
    CONTAINS(LCASE(STR(?litVal)), "merkitse varus")
  )
}
LIMIT 25
